// Merge all regulatory updates and parse changes
const sebiData = $('Fetch SEBI CSCRF Updates').first().json;
const lgpdData = $('Fetch LGPD/ANPD Updates').first().json;
const jointData = $('Fetch SA Joint Standard Updates').first().json;

const allUpdates = [];

// Process SEBI updates
if (sebiData.updates && sebiData.updates.length > 0) {
  for (const update of sebiData.updates) {
    allUpdates.push({
      source: 'SEBI_CSCRF',
      region: 'India',
      title: update.title,
      summary: update.summary,
      severity: update.severity || 'info',
      effectiveDate: update.effectiveDate,
      url: update.url,
      categories: update.categories || [],
      publishedAt: update.publishedAt
    });
  }
}

// Process LGPD updates
if (lgpdData.updates && lgpdData.updates.length > 0) {
  for (const update of lgpdData.updates) {
    allUpdates.push({
      source: 'LGPD_ANPD',
      region: 'Brazil',
      title: update.title,
      summary: update.summary,
      severity: update.severity || 'info',
      effectiveDate: update.effectiveDate,
      url: update.url,
      categories: update.categories || [],
      publishedAt: update.publishedAt
    });
  }
}

// Process Joint Standard updates
if (jointData.updates && jointData.updates.length > 0) {
  for (const update of jointData.updates) {
    allUpdates.push({
      source: 'JOINT_STANDARD_SA',
      region: 'South Africa',
      title: update.title,
      summary: update.summary,
      severity: update.severity || 'info',
      effectiveDate: update.effectiveDate,
      url: update.url,
      categories: update.categories || [],
      publishedAt: update.publishedAt
    });
  }
}

return [{
  json: {
    totalUpdates: allUpdates.length,
    updates: allUpdates,
    checkedAt: new Date().toISOString(),
    hasChanges: allUpdates.length > 0
  }
}];

// Build Telegram alert messages per affected client
const comparison = $input.first().json;
const affectedClients = comparison.affectedClients || [];
const updates = $('Parse & Merge Regulatory Changes').first().json.updates;

const messages = [];

if (affectedClients.length > 0) {
  for (const client of affectedClients) {
    const relevantUpdates = updates.filter(u => 
      client.regions.includes(u.region) || 
      client.frameworks.includes(u.source)
    );

    let alertText = `🚨 *Compliance Alert — ${client.name}*\n\n`;
    alertText += `${relevantUpdates.length} regulatory change(s) affect your configuration:\n\n`;

    for (const update of relevantUpdates) {
      const severityEmoji = {
        critical: '🔴',
        high: '🟠',
        medium: '🟡',
        low: '🟢',
        info: 'ℹ️'
      }[update.severity] || 'ℹ️';

      alertText += `${severityEmoji} *${update.source}* — ${update.title}\n`;
      alertText += `   ${update.summary.substring(0, 200)}\n`;
      if (update.effectiveDate) {
        alertText += `   📅 Effective: ${update.effectiveDate}\n`;
      }
      alertText += `\n`;
    }

    alertText += `📋 Action required: Review and update your compliance configuration.`;

    messages.push({
      chatId: client.telegramChatId,
      text: alertText,
      clientId: client.id
    });
  }
} else {
  // Summary for admin channel
  let summaryText = `✅ *Daily Compliance Check — No Client Impact*\n\n`;
  summaryText += `📅 ${new Date().toISOString().split('T')[0]}\n`;
  summaryText += `📊 ${updates.length} update(s) reviewed\n`;
  summaryText += `👥 0 clients affected\n`;

  messages.push({
    chatId: process.env.ADMIN_TELEGRAM_CHAT_ID,
    text: summaryText,
    clientId: 'admin'
  });
}

return messages.map(m => ({ json: m }));

// Log compliance check results
const updates = $('Parse & Merge Regulatory Changes').first().json;
const comparison = $input.first()?.json || {};

return [{
  json: {
    event: 'compliance_check_complete',
    timestamp: new Date().toISOString(),
    totalUpdates: updates.totalUpdates,
    affectedClients: comparison.affectedClients?.length || 0,
    sources: ['SEBI_CSCRF', 'LGPD_ANPD', 'JOINT_STANDARD_SA']
  }
}];
